r($,"b0Q","yz",()=>{var q="Community",p=2026,o="MCA Admin"
return A.a([A.Nq("MCA Editorial",'The Macedonian Community of Australia Inc. celebrated its 50th anniversary with a grand gala event held at the Melbourne Convention Centre. Over 2,000 community members attended the event, which featured traditional music, dance performances, and speeches from community leaders and government officials.\n\nThe evening showcased the rich cultural heritage of the Macedonian diaspora in Australia, highlighting decades of contributions to Australian multicultural society. Traditional folk ensembles performed oro dances, while renowned musicians played classic Macedonian songs that had the audience singing along.\n\n"This milestone represents not just 50 years of organization, but 50 years of preserving our identity, language, and traditions in our adopted homeland," said the community president in his opening address.',"\u041c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0430\u0442\u0430 \u0437\u0430\u0435\u0434\u043d\u0438\u0446\u0430 \u043d\u0430 \u0410\u0432\u0441\u0442\u0440\u0430\u043b\u0438\u0458\u0430 \u043f\u0440\u043e\u0441\u043b\u0430\u0432\u0443\u0432\u0430 50 \u0433\u043e\u0434\u0438\u043d\u0438 \u0441\u043e \u0433\u043e\u043b\u0435\u043c \u0433\u0430\u043b\u0430 \u043d\u0430\u0441\u0442\u0430\u043d \u043e\u0434\u0440\u0436\u0430\u043d \u0432\u043e \u041a\u043e\u043d\u0432\u0435\u043d\u0446\u0438\u0441\u043a\u0438\u043e\u0442 \u0446\u0435\u043d\u0442\u0430\u0440 \u0432\u043e \u041c\u0435\u043b\u0431\u0443\u0440\u043d. \u041d\u0430\u0434 2.000 \u0447\u043b\u0435\u043d\u043e\u0432\u0438 \u043d\u0430 \u0437\u0430\u0435\u0434\u043d\u0438\u0446\u0430\u0442\u0430 \u043f\u0440\u0438\u0441\u0443\u0441\u0442\u0432\u0443\u0432\u0430\u0430 \u043d\u0430 \u043d\u0430\u0441\u0442\u0430\u043d\u043e\u0442, \u043a\u043e\u0458 \u0432\u043a\u043b\u0443\u0447\u0443\u0432\u0430\u0448\u0435 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043e\u043d\u0430\u043b\u043d\u0430 \u043c\u0443\u0437\u0438\u043a\u0430, \u0442\u0430\u043d\u0446\u043e\u0432\u0438 \u043f\u0440\u0435\u0442\u0441\u0442\u0430\u0432\u0438 \u0438 \u0433\u043e\u0432\u043e\u0440\u0438 \u043e\u0434 \u043b\u0438\u0434\u0435\u0440\u0438 \u043d\u0430 \u0437\u0430\u0435\u0434\u043d\u0438\u0446\u0430\u0442\u0430 \u0438 \u0432\u043b\u0430\u0434\u0438\u043d\u0438 \u0444\u0443\u043d\u043a\u0446\u0438\u043e\u043d\u0435\u0440\u0438.\n\n\u0412\u0435\u0447\u0435\u0440\u0442\u0430 \u0433\u043e \u043f\u043e\u043a\u0430\u0436\u0430 \u0431\u043e\u0433\u0430\u0442\u043e\u0442\u043e \u043a\u0443\u043b\u0442\u0443\u0440\u043d\u043e \u043d\u0430\u0441\u043b\u0435\u0434\u0441\u0442\u0432\u043e \u043d\u0430 \u043c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0430\u0442\u0430 \u0434\u0438\u0458\u0430\u0441\u043f\u043e\u0440\u0430 \u0432\u043e \u0410\u0432\u0441\u0442\u0440\u0430\u043b\u0438\u0458\u0430.",q,"https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=800","n1",A.dB(p,3,25,0,0,0,0),5,"Macedonian Community Celebrates 50th Anniversary in Melbourne","\u041c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0430\u0442\u0430 \u0437\u0430\u0435\u0434\u043d\u0438\u0446\u0430 \u043f\u0440\u043e\u0441\u043b\u0430\u0432\u0443\u0432\u0430 50 \u0433\u043e\u0434\u0438\u043d\u0438 \u0432\u043e \u041c\u0435\u043b\u0431\u0443\u0440\u043d"),A.Nq(o,"Macedonian language classes for children and adults will begin next month at the community center in Sydney. The program aims to preserve the Macedonian language among younger generations. Classes will be offered at beginner, intermediate, and advanced levels.\n\nRegistrations are now open for all age groups. Children aged 5-12 will have Saturday morning classes, while teenagers and adults can choose from evening sessions during the week.","\u0427\u0430\u0441\u043e\u0432\u0438 \u043f\u043e \u043c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0438 \u0458\u0430\u0437\u0438\u043a \u0437\u0430 \u0434\u0435\u0446\u0430 \u0438 \u0432\u043e\u0437\u0440\u0430\u0441\u043d\u0438 \u045c\u0435 \u043f\u043e\u0447\u043d\u0430\u0442 \u0441\u043b\u0435\u0434\u043d\u0438\u043e\u0442 \u043c\u0435\u0441\u0435\u0446 \u0432\u043e \u0446\u0435\u043d\u0442\u0430\u0440\u043e\u0442 \u043d\u0430 \u0437\u0430\u0435\u0434\u043d\u0438\u0446\u0430\u0442\u0430 \u0432\u043e \u0421\u0438\u0434\u043d\u0435\u0458. \u041f\u0440\u043e\u0433\u0440\u0430\u043c\u0430\u0442\u0430 \u0438\u043c\u0430 \u0437\u0430 \u0446\u0435\u043b \u0434\u0430 \u0433\u043e \u0437\u0430\u0447\u0443\u0432\u0430 \u043c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0438\u043e\u0442 \u0458\u0430\u0437\u0438\u043a \u043c\u0435\u0453\u0443 \u043f\u043e\u043c\u043b\u0430\u0434\u0438\u0442\u0435 \u0433\u0435\u043d\u0435\u0440\u0430\u0446\u0438\u0438.",q,"https://images.unsplash.com/photo-1503676260728-1c00da094a0b?w=800","n2",A.dB(p,3,22,0,0,0,0),3,"New Macedonian Language Classes Starting in Sydney","\u041d\u043e\u0432\u0438 \u0447\u0430\u0441\u043e\u0432\u0438 \u043f\u043e \u043c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0438 \u0458\u0430\u0437\u0438\u043a \u043f\u043e\u0447\u043d\u0443\u0432\u0430\u0430\u0442 \u0432\u043e \u0421\u0438\u0434\u043d\u0435\u0458"),A.Nq(o,"A talented young Australian-Macedonian footballer has signed a professional contract with Melbourne Victory in the A-League. The 19-year-old midfielder, who grew up playing for the local Macedonian community football club, will join the first team squad for the upcoming season.\n\nThe signing represents a proud moment for the Macedonian community in Australia, with many hoping it will inspire more young players from the community.","\u0422\u0430\u043b\u0435\u043d\u0442\u0438\u0440\u0430\u043d \u043c\u043b\u0430\u0434 \u0430\u0432\u0441\u0442\u0440\u0430\u043b\u0438\u0441\u043a\u043e-\u043c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0438 \u0444\u0443\u0434\u0431\u0430\u043b\u0435\u0440 \u043f\u043e\u0442\u043f\u0438\u0448\u0430 \u043f\u0440\u043e\u0444\u0435\u0441\u0438\u043e\u043d\u0430\u043b\u0435\u043d \u0434\u043e\u0433\u043e\u0432\u043e\u0440 \u0441\u043e \u041c\u0435\u043b\u0431\u0443\u0440\u043d \u0412\u0438\u043a\u0442\u043e\u0440\u0438 \u0432\u043e \u0410-\u041b\u0438\u0433\u0430\u0442\u0430.","Sports","https://images.unsplash.com/photo-1431324155629-1a6deb1dec8d?w=800","n3",A.dB(p,3,20,0,0,0,0),4,"Australian-Macedonian Footballer Signs with A-League Club","\u0410\u0432\u0441\u0442\u0440\u0430\u043b\u0438\u0441\u043a\u043e-\u043c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0438 \u0444\u0443\u0434\u0431\u0430\u043b\u0435\u0440 \u043f\u043e\u0442\u043f\u0438\u0448\u0430 \u0441\u043e \u0410-\u041b\u0438\u0433\u0430 \u043a\u043b\u0443\u0431"),A.Nq(o,"Macedonian food lovers united at the annual multicultural food festival in Brisbane, where traditional Macedonian cuisine was a highlight. Vendors served favorites including tavche gravche, ajvar, zelnik, and burek, alongside grilled meats and pastries.\n\nThe Macedonian stalls drew long queues throughout the weekend event, with many non-Macedonian Australians discovering the rich flavors for the first time.","\u0409\u0443\u0431\u0438\u0442\u0435\u043b\u0438\u0442\u0435 \u043d\u0430 \u043c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0430 \u0445\u0440\u0430\u043d\u0430 \u0441\u0435 \u043e\u0431\u0435\u0434\u0438\u043d\u0438\u0458\u0430 \u043d\u0430 \u0433\u043e\u0434\u0438\u0448\u043d\u0438\u043e\u0442 \u043c\u0443\u043b\u0442\u0438\u043a\u0443\u043b\u0442\u0443\u0440\u0435\u043d \u0444\u0435\u0441\u0442\u0438\u0432\u0430\u043b \u0437\u0430 \u0445\u0440\u0430\u043d\u0430 \u0432\u043e \u0411\u0440\u0438\u0437\u0431\u0435\u0458\u043d.","Culture","https://images.unsplash.com/photo-1555939594-58d7cb561ad1?w=800","n4",A.dB(p,3,18,0,0,0,0),3,"Traditional Macedonian Cuisine Takes Center Stage at Food Festival","\u0422\u0440\u0430\u0434\u0438\u0446\u0438\u043e\u043d\u0430\u043b\u043d\u0430\u0442\u0430 \u043c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0430 \u043a\u0443\u0458\u043d\u0430 \u0432\u043e \u0446\u0435\u043d\u0442\u0430\u0440\u043e\u0442 \u043d\u0430 \u0444\u0435\u0441\u0442\u0438\u0432\u0430\u043b \u0437\u0430 \u0445\u0440\u0430\u043d\u0430"),A.Nq(o,"The Macedonian community center in Perth has undergone a major renovation, with modern facilities now available for events, meetings, and cultural activities. The upgraded center features a new performance hall, commercial kitchen, and multimedia room.","\u0426\u0435\u043d\u0442\u0430\u0440\u043e\u0442 \u043d\u0430 \u043c\u0430\u043a\u0435\u0434\u043e\u043d\u0441\u043a\u0430\u0442\u0430 \u0437\u0430\u0435\u0434\u043d\u0438\u0446\u0430 \u0432\u043e \u041f\u0435\u0440\u0442 \u043f\u043e\u043c\u0438\u043d\u0430 \u043d\u0438\u0437 \u0433\u043e\u043b\u0435\u043c\u0430 \u0440\u0435\u043d\u043e\u0432\u0430\u0446\u0438\u0458\u0430.",q,"https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?w=800","n5",A.dB(p,3,15,0,0,0,0),2,"Community Center Renovations Complete in Perth","\u0420\u0435\u043d\u043e\u0432\u0438\u0440\u0430\u045a\u0435\u0442\u043e \u043d\u0430 \u0446\u0435\u043d\u0442\u0430\u0440\u043e\u0442 \u043d\u0430 \u0437\u0430\u0435\u0434\u043d\u0438\u0446\u0430\u0442\u0430 \u0432\u043e \u041f\u0435\u0440\u0442 \u0435 \u0437\u0430\u0432\u0440\u0448\u0435\u043d\u043e")],A.ai("C<ik>"))})
